n,k,p=map(int,input().split())
a=list(map(int,input().split()))

s=sum(a)
if s%2==1 or k>n or p>k:
    print('NO')
    exit(0)

a.sort(reverse=True)

c=0
for i in range(n):
    if a[i]%2==0:
        c+=1

if c<p or c>k:
    print('NO')
    exit(0)

ans=[[] for i in range(k)]

for i in range(n):
    if a[i]%2==0:
        ans[p-1].append(a[i])
        p-=1
    else:
        ans[k-1].append(a[i])
        k-=1

print('YES')
for i in ans:
    print(len(i),*i)
